      /* ---- Nav chrome glyphs (added v3.23 — the nav-header's JS-injected
         controls render from this sprite instead of raw emoji (📌 ☰ ✕ ⎘ 📂),
         which ignored currentColor/theming and rendered differently per
         platform; see #426) */
      menu:       '<line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/>',
      pin:        '<path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/>',
